// Récupération des métadonnées essentielles et de la première pièce jointe PDF
const items = $input.all();
const out = [];

for (const it of items) {
  const json = it.json || {};
  const binary = it.binary || {};

  // Identifier le binaire PDF
  let pdfKey = null;
  for (const key of Object.keys(binary)) {
    const b = binary[key];
    const mt = (b.mimeType || '').toLowerCase();
    const fn = (b.fileName || '').toLowerCase();
    if (mt.includes('pdf') || fn.endsWith('.pdf')) {
      pdfKey = key;
      break;
    }
  }

  if (!pdfKey) continue;

  const fromHeader = json.from?.value?.[0] || {};
  const senderEmail = fromHeader.address || json.From || '';
  const senderName = fromHeader.name || senderEmail.split('@')[0] || 'Client';
  const subject = json.subject || json.Subject || 'Sans objet';
  const messageId = json.id || json.messageId || '';

  out.push({
    json: {
      sender_email: senderEmail,
      sender_name: senderName,
      subject,
      message_id: messageId,
      received_at: new Date().toISOString(),
      pdf_binary_key: pdfKey
    },
    binary: { data: binary[pdfKey] }
  });
}

return out;

// Normalise le texte OCR — qu'il vienne du PDF natif ou de Vision
const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json || {};
  let text = '';
  if (typeof j.text === 'string' && j.text.trim().length > 0) {
    text = j.text;
  } else if (j.responses && j.responses[0]?.fullTextAnnotation?.text) {
    text = j.responses[0].fullTextAnnotation.text;
  }
  out.push({ json: { ...j, ocr_text: text } });
}
return out;

// Parse + valide la sortie GPT, calcule les valeurs manquantes
const items = $input.all();
const out = [];

for (const it of items) {
  const j = it.json || {};
  let parsed = j.message?.content || j.content || j;
  if (typeof parsed === 'string') {
    const clean = parsed.replace(/```json|```/g, '').trim();
    try { parsed = JSON.parse(clean); } catch (e) { parsed = {}; }
  }

  const num = (v) => {
    if (typeof v === 'number') return v;
    if (!v) return 0;
    const s = String(v).replace(/\s/g, '').replace(',', '.').replace(/[^0-9.\-]/g, '');
    const n = parseFloat(s);
    return isNaN(n) ? 0 : n;
  };

  const total_ht = num(parsed.total_ht);
  const tva_rate = num(parsed.tva_rate) || 20;
  const tva_amount = num(parsed.tva_amount) || +(total_ht * (tva_rate / 100)).toFixed(2);
  const total_ttc = num(parsed.total_ttc) || +(total_ht + tva_amount).toFixed(2);

  out.push({
    json: {
      ...it.json,
      invoice: {
        vendor_name: parsed.vendor_name || '',
        vendor_ice: parsed.vendor_ice || '',
        client_name: parsed.client_name || '',
        client_ice: parsed.client_ice || '',
        invoice_number: parsed.invoice_number || `INV-${Date.now()}`,
        invoice_date: parsed.invoice_date || new Date().toISOString().slice(0, 10),
        due_date: parsed.due_date || null,
        line_items: Array.isArray(parsed.line_items) ? parsed.line_items : [],
        total_ht: +total_ht.toFixed(2),
        tva_rate,
        tva_amount: +tva_amount.toFixed(2),
        total_ttc: +total_ttc.toFixed(2),
        currency: parsed.currency || 'MAD'
      },
      parse_ok: total_ht > 0
    }
  });
}
return out;

// Extrait le cookie de session et prépare le payload account.move
const items = $input.all();
const out = [];

for (const it of items) {
  const headers = it.json.headers || {};
  const setCookie = headers['set-cookie'] || headers['Set-Cookie'] || [];
  const cookieArr = Array.isArray(setCookie) ? setCookie : [setCookie];
  const sessionCookie = cookieArr
    .map(c => String(c).split(';')[0])
    .filter(c => c.startsWith('session_id='))
    .join('; ');

  // Récupère les données facture depuis les nœuds précédents
  const inv = $('Valider données IA').first().json.invoice;
  const meta = $('Préparer données email').first().json;

  // Construire les lignes d'écriture (account.move.line)
  const ref = `${inv.vendor_name} — ${inv.invoice_number}`;
  const lines = [
    // Débit client TTC (3421)
    [0, 0, {
      name: ref,
      account_id: 3421,
      debit: inv.total_ttc,
      credit: 0
    }],
    // Crédit produit HT (7111)
    [0, 0, {
      name: ref,
      account_id: 7111,
      debit: 0,
      credit: inv.total_ht
    }],
    // Crédit TVA collectée (4455)
    [0, 0, {
      name: ref,
      account_id: 4455,
      debit: 0,
      credit: inv.tva_amount
    }]
  ];

  out.push({
    json: {
      session_cookie: sessionCookie,
      auth_ok: !!sessionCookie,
      move_payload: {
        ref: inv.invoice_number,
        date: inv.invoice_date,
        move_type: 'out_invoice',
        narration: `Facture ${inv.vendor_name} — ICE ${inv.vendor_ice}`,
        line_ids: lines
      },
      invoice: inv,
      meta
    }
  });
}
return out;

// Récupère l'ID de l'écriture créée et enrichit les données
const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json || {};
  const result = j.result;
  const odoo_entry_id = (typeof result === 'number') ? result : (Array.isArray(result) ? result[0] : null);
  const error = j.error || null;

  const prev = $('Préparer écriture Odoo').first().json;

  out.push({
    json: {
      odoo_entry_id,
      odoo_ok: !!odoo_entry_id && !error,
      odoo_error: error,
      invoice: prev.invoice,
      meta: prev.meta
    }
  });
}
return out;

// Branche d'erreur : prépare l'email de secours avec le texte OCR brut
const items = $input.all();
const out = [];
for (const it of items) {
  const meta = $('Préparer données email').first().json;
  const ocrText = ($('Normaliser texte OCR').first().json.ocr_text) || '(aucun texte extrait)';
  const invoice = it.json.invoice || {};
  out.push({
    json: {
      meta,
      ocr_text: ocrText,
      invoice,
      error_stage: it.json.odoo_error ? 'Odoo' : (it.json.parse_ok === false ? 'Analyse IA' : 'OCR')
    }
  });
}
return out;
